head.script:
/*
1. 과세구분 코드값 처리
name=과세구분  width=120 align=center sort=true EditStyle=Combo Data="<%= GauceUtil.getGridCombo("SD070", true) %>" </c>
*/


scwin.empNo = "'";
scwin.vCurDate = WebSquare.date.getCurrentServerDate("yyyyMMdd");  // 서버를 기준으로 현재 날짜 반환
scwin.vQryStDt = scwin.vCurDate.substring(0, 6) + "01";  // 조회시작일자(현재 날짜가 포함된 달의 시작 일자)
scwin.vQryEndDt = scwin.vCurDate.substring(0, 6) + new Date(scwin.vCurDate.substring(0, 4), scwin.vCurDate.substring(4, 6) , 0).getDate();;  // 조회종료일자(현재 날짜가 포함된 달의 마지막 일자)
//var lastDay = new Date(scwin.vCurDate.substring(0, 4), scwin.vCurDate.substring(4, 2), 0).getDate();

scwin.onpageload = function() {
    let memJson = $c.data.getMemInfo();
    console.log(memJson);
    scwin.empNo = memJson.userId;

    const codeOptions = [
        { grpCd: "SD070", compID: "gr_List:taxnClsCd" }   // 과세구분
    ]
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        udc_comCode.hide();

        scwin.f_SetDefaultData();

    }, {"delay":50});
};

scwin.f_SetDefaultData = function () {
    ed_brthngRateStDt.setValue(scwin.vQryStDt);  // 적용일자시작
    ed_brthngRateEndDt.setValue(scwin.vQryEndDt);  // 적용일자종료	

    ////임시
    //ed_brthngRateStDt.setValue('20080501');
    //ed_brthngRateEndDt.setValue('20080601');
    ////임시	
}

scwin.f_Retrieve = async function () { 
    var chkVal = await $c.gus.cfValidate([ed_brthngRateStDt,ed_brthngRateEndDt]);
    if (!chkVal){
        return;
    }
    var chkCal = await scwin.f_termChk(ed_brthngRateStDt, ed_brthngRateEndDt);
    if (chkCal) {
        return;	
    }

    $c.sbm.execute(sbm_condition);
}

scwin.f_termChk = async function (stObj, endObj) {
    if ( stObj.getValue().trim() > endObj.getValue().trim() ) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_045, ['입항(예정)일자'] );	//기간 체크
        stObj.focus();
        return true;
    }
    return false;
} 


//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------

scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    var rtnList;  // 공통POP-UP -> 요청화면 

    switch (disGubun){

        case 1: // 본선관리번호검색 팝업
            //var win_url = "/to/in/fs/bilg/in_701_01_02p.jsp?paramTitle=본선관리번호검색팝업";
            var win_url = "/ui/to/in/fs/bilg/in_701_01_02p.xml";

            //var win_style = "dialogWidth:885px; dialogHeight:425px";
            var opts = scwin.opts || {};
            opts.modal = true;
            opts.type = "browserPopup";
            opts.id = scwin.popupID || "pupup";
            opts.width = 1300;
            opts.height = 625;
            opts.popupName = '접안료본선팝업';

            var arrParam = {
                arrParam0 : ed_cvsslMgntNo.getValue(),
                arrParam1 : ""
            }

            //var rtnList = window.showModalDialog(win_url, arrParm, win_style);
            rtnList = await $c.win.openPopup(win_url, opts, arrParam);
            console.log("rtnList : " , rtnList);

            if(rtnList != null && rtnList[0] != "" && rtnList != "N/A") {
                ed_cvsslMgntNo.setValue(rtnList[0]);
            } else {
                ed_cvsslMgntNo.setValue("");
            }
            break;

        case 2: // 본선관리번호검색 팝업

            var win_url = "/ui/to/in/fs/bilg/in_701_01_02p.xml";
            var opts = scwin.opts || {};
            opts.modal = true;
            opts.type = "browserPopup";
            opts.id = scwin.popupID || "pupup";
            opts.width = 1300;
            opts.height = 625;
            opts.popupName = '접안료본선팝업';

            var arrParam = {
                arrParam0 : pCode,
                arrParam1 : ""
            }

            rtnList = await $c.win.openPopup(win_url, opts, arrParam);

            if(rtnList != null && rtnList[0] != "" && rtnList != "N/A") {
                $c.gus.f_SetGridReturnValue(rtnList, ds_List, ds_List.getRowPosition(), 
                ["cvsslMgntNo","lobranCd","lobranNm","vsslCd","vsslNm","mrn","vsslPurpsNm","portCd","pierCd","pierNm","arvDtm"     
                ,"dptDtm","alngpierDtm","offpierDtm" ,"adptHh","agrWt","ocshipYn","ocshipNm"]);
            }
            break;

        case 3: //화주 팝업	

            rtnList = udc_comCode.cfCommonPopUp(scwin.callbackClntInfo	// XML상의 SELECT ID	
                                    ,pCode			// 화면에서의 ??? Code Element의	Value
                                    ,pName			// 화면에서의 ??? Name Element의	Value
                                    ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null					// Title순서	
                                    ,null					// 보여주는 각 컬럼들의 폭	
                                    ,null					// 컬럼중에서 숨기는	컬럼 지정	
                                    ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                                    ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                    ,null					// 윈도우 위치 Y좌표	
                                    ,null					// 윈도우 위치 X좌표
                                    ,null					// 중복체크여부	("F")
                                    ,'F'					// 전체검색허용여부	("F")
                                    ,"화주,화주코드,화주명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    );


            /*
            if (ret != null && ret[0] != "") {
                ds_List.setCellData(ds_List.getRowPosition() ,'clntNo', ret[0]);
                ds_List.setCellData(ds_List.getRowPosition() ,'clntNm', ret[1]);
            }
            */
            break;								
    }
}

scwin.callbackClntInfo = function (rtnList) {
    if (rtnList != null && rtnList[0] != "") {
        ds_List.setCellData(ds_List.getRowPosition() ,'clntNo', rtnList[0]);
        ds_List.setCellData(ds_List.getRowPosition() ,'clntNm', rtnList[1]);
    } else {
        ds_List.setCellData(ds_List.getRowPosition() ,'clntNo', "");
        ds_List.setCellData(ds_List.getRowPosition() ,'clntNm', "");
    }
}



// ----------------------------------------------------------------------
//행 삭제
//-----------------------------------------------------------------------
scwin.f_delRow = function () {
    if(ds_List.getRowCount() == 0){
        $c.win.alert("삭제할 데이타가 없습니다");
    } else {
        ds_List.removeRow(gr_List.getFocusedRowIndex());
    }
}

//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    ed_brthngRateStDt.setValue(scwin.vQryStDt);  // 적용일자시작
    ed_brthngRateEndDt.setValue(scwin.vQryEndDt);  // 적용일자종료	
	ed_cvsslMgntNo.setValue("");

}


scwin.f_Sell =  async function () {
    if(ds_List.getRowCount() == 0) {
        $c.win.alert("매출생성할 내용이 없습니다.");
        return;
    } else {
        var chkGrList = await $c.gus.cfValidate([gr_List]);
        if (!chkGrList) {
            return;
        }

		var insideOcshipClsCd;
        if(ds_List.getCellData(ds_List.getRowPosition(),"ocshipYn")==1) {
            insideOcshipClsCd="O";
        } else {
            insideOcshipClsCd="I";
        }
        /*
        if($c.win.confirm("매출 생성 하시겠습니까?") == true) {
            ds_BrthngRate.setCellData(0,"insideOcshipClsCd", insideOcshipClsCd);
            $c.sbm.execute(sbm_brthngRate);
        }
        */
        var confirm = await $c.win.confirm("매출 생성 하시겠습니까?");
        if(confirm) {
            ds_BrthngRate.removeAll();
            ds_BrthngRate.insertRow(0);
            ds_BrthngRate.setRowPosition(ds_BrthngRate.getRowCount()-1);
            ds_BrthngRate.setCellData(0,"insideOcshipClsCd", insideOcshipClsCd);

            $c.sbm.execute(sbm_brthngRate);
        }
    }
}

scwin.f_Caln = function (rowCnt) {

	var num=0;
	var amt=0;	
	var amt1=0;
	var totAmt=0;
	var adptHhCd=0;
	for(var i=0 ; i < rowCnt ; i++) {
	//기본료
		if(ds_List1.getCellData(i,'alngpierTrfClsCd') == 0)
		{
            amt=amt+(ds_List1.getCellData(i,'trf') * (ds_List.getCellData(ds_List.getRowPosition(),'agrWt')/parseInt(ds_List1.getCellData(i,'adptTonCd'))));
			adptHhCd = parseInt(ds_List1.getCellData(i,'adptHhCd'));

		} else {
            if(adptHhCd	<  ds_List.getCellData(ds_List.getRowPosition(),'adptHh')) {
			    num=ds_List.getCellData(ds_List.getRowPosition(),'adptHh') - adptHhCd;
				amt=amt+num*(ds_List1.getCellData(i,'trf') * (ds_List.getCellData(ds_List.getRowPosition(),'agrWt')/parseInt(ds_List1.getCellData(i,'adptTonCd'))));
            }
		}
	}
    console.log("ds_List.getRowPosition() : " , ds_List.getRowPosition());
	ds_List.setCellData(ds_List.getRowPosition(),'alngpierAmt', Math.floor(amt/10)*10);

	if(ds_List.getCellData(ds_List.getRowPosition(),'taxnClsCd')=='02') {
		ds_List.setCellData(ds_List.getRowPosition(),'alngpierVat',0);
	} else {
		ds_List.setCellData(ds_List.getRowPosition(),'alngpierVat',Math.floor(amt/10));
	}
}


scwin.f_Save = async function () {
    var chkGrd = await $c.gus.cfValidate([gr_List]);
    if (!chkGrd) return;

    if(ds_List.getModifiedIndex().length < 1) {
        $c.win.alert("변경된 정보가 없습니다.");	//변경된 정보가 없습니다.
        return;
    }

    for(var i=0 ; i < ds_List.getRowCount() ; i++) {
        if(ds_List.getRowStatus(i) == "U") {
            //alert("U row : "+ (i+1));
            $c.win.alert("수정할수 없습니다.삭제후 등록하세요");
            ds_List.undoRow(i);
            //return;					
        }

        if(ds_List.getCellData(i,'alngpierAmt') == 0 || ds_List.getCellData(i,'alngpierAmt') == "") {
            $c.win.alert((i+1)+"번째 금액을 넣어주세요");
            return;
        }
    }

    ////////////////////// 임시 start ///////////////////////
    /*
    for(var i=0 ; i < ds_List.getRowCount() ; i++) {

        if(ds_List.getRowStatus(i) == "C"){
            alert("taxnClsCd 02 done");
            ds_List.setCellData(i, "taxnClsCd", "02");
        }
    }
    */
    ////////////////////// 임시 end ///////////////////////




    var confirm = await $c.win.confirm(MSG_CM_CRM_001);
    if(confirm) {
        $c.sbm.execute(sbm_save);
    }

}





scwin.btn_conCvsslMgntNo_onclick = function (e) {
    scwin.f_openCommonPopUp(1, 'ed_cvsslMgntNo.getValue()', '','T','F');
};

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
    //ed_cvsslMgntNo.show("block");
};

scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
    //ed_cvsslMgntNo.show("inline");
};

scwin.btn_Save_onclick = function (e) {
    scwin.f_Sell();
};

scwin.btn_save1_onclick = function (e) {
    scwin.f_Save();
};

scwin.gr_List_ontextimageclick = function (row, col) {
    var columnId = gr_List.getColumnID(col);

    if(columnId == "cvsslMgntNo") {
		scwin.f_openCommonPopUp(2,ds_List.getCellData(row,columnId),'','T','T');
    } else if(columnId == "clntNm") {
        scwin.f_openCommonPopUp(3,ds_List.getCellData(row,'clntNo'),ds_List.getCellData(row,columnId),'T','T');
    }
};

scwin.sbm_condition_submitdone = function (e) {
    if(ds_List.getRowCount() == 0){
        $c.win.alert(MSG_CM_ERR_003);
    }
    spa_totalRows.setValue(ds_List.getRowCount());
};

scwin.sbm_brthngRate_submitdone = function (e) {
    if(ds_List1.getRowCount() ==0){
    	$c.win.alert("접안료등록을 먼저 하십시요.");  // 해당되는 자료가 존재하지 않습니다	
    }  else {
    	scwin.f_Caln(ds_List1.getRowCount());
    }
};

scwin.gr_List_onviewchange = function (info) {
    console.log(info);
    var row = info.rowIndex;
    var columnId = info.colId;

    if(columnId == "cvsslMgntNo") {
		scwin.f_openCommonPopUp(2,ds_List.getCellData(row,columnId),'','','T');
    } else if(columnId == "clntNm") {
        scwin.f_openCommonPopUp(3,ds_List.getCellData(row,'clntNo'),ds_List.getCellData(row,columnId),'','T');
    }
};

//-------------------------------------------------------------------------
// 대문자 입력
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};

scwin.gr_List_oneditkeyup = function (info) {
    const inputEl = event.target;

    switch (info.colID) {
        case "cvsslMgntNo" :        
            inputEl.value = info.newValue.toUpperCase();
            break;
        default :
            break;
    }
};


scwin.sbm_save_submitdone = function (e) {
    console.log(e.responseJSON.resultDataSet);
    if(e.responseJSON.resultDataSet[0].Code == 0) {
   	    $c.win.alert(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
	    scwin.f_Retrieve();
    }
};
